```class Solution {
public:
    int numSub(string s) {
        int res = 0, cnt = 0, mod = 1e9 + 7;
        for (char c : s) {
            cnt = (c == '1' ? cnt + 1 : 0);
            res = (res + cnt) % mod;
        }
        return res;
    }
};
